static void compute_md6_128(const unsigned char *pass, int passlen,
    const unsigned char *salt, int saltlen, unsigned char *dest)
{
    (void)salt; (void)saltlen;
    md6_hash(128, (unsigned char *)pass, (uint64_t)passlen * 8, dest);
}

