    /* HTV: register a non-hex verify type (vclass defaults to HCLASS_ALL) */
    #define HTV(tname, fl, vfn, ex) do { \
        int _i = find_type_index(tname); \
        if (_i >= 0) { \
            Hashtypes[_i].hashlen = 0; \
